import { supabase } from '../../utils/supabaseClient';
import { normalizarPerfil, Perfil, type Usuario } from '../../classes';

type ProfileRow = {
  id: string;
  nome?: string | null;
  email: string;
  perfil?: string | null;
  funcao?: string | null;
  formacao?: string | null;
  matricula?: number | string | null;
  curso?: string | null;
  criado_em?: string;
  atualizado_em?: string;
};

function parseMatriculaDb(valor: unknown): number | null {
  if (valor === null || valor === undefined || valor === '') return null;
  const numero = typeof valor === 'number' ? valor : Number(String(valor).trim());
  return Number.isFinite(numero) ? numero : null;
}

function fromDbRow(row: ProfileRow): Usuario {
  return {
    id: row.id,
    nome: String(row.nome || '').trim(),
    email: row.email,
    perfil: normalizarPerfil(row.perfil),
    funcao: row.funcao ?? null,
    formacao: row.formacao ?? null,
    matricula: parseMatriculaDb(row.matricula),
    curso: row.curso ?? null,
    criado_em: row.criado_em,
    atualizado_em: row.atualizado_em,
  };
}

function toDbRow(userData: Partial<Usuario>): Partial<ProfileRow> {
  const row: Partial<ProfileRow> = {};

  if (userData.id !== undefined) row.id = userData.id;
  if (userData.nome !== undefined) row.nome = userData.nome;
  if (userData.email !== undefined) row.email = userData.email;
  if (userData.perfil !== undefined) row.perfil = normalizarPerfil(userData.perfil);
  if (userData.funcao !== undefined) row.funcao = userData.funcao;
  if (userData.formacao !== undefined) row.formacao = userData.formacao;
  if (userData.matricula !== undefined) row.matricula = userData.matricula;
  if (userData.curso !== undefined) row.curso = userData.curso;
  if (userData.criado_em !== undefined) row.criado_em = userData.criado_em;
  if (userData.atualizado_em !== undefined) row.atualizado_em = userData.atualizado_em;

  return row;
}

const UsuarioDAO = {
  async PesquisaUsuario() {
    const { data, error } = await supabase
      .from('Usuario')
      .select('*')
      .order('criado_em', { ascending: false });
    if (error) throw error;
    return data as Usuario[];
  },

  async PesquisaUsuarioPorId(id: string) {
    const { data, error } = await supabase
      .from('Usuario')
      .select('*')
      .eq('id', id)
      .single();
    if (error) throw error;
    return data as Usuario;
  },

  async PesquisaUsuarioPorIdOpcional(id: string) {
    const { data, error } = await supabase
      .from('Usuario')
      .select('*')
      .eq('id', id)
      .maybeSingle();
    if (error) throw error;
    return data as Usuario | null;
  },

  async CadastroUsuario(userData: Partial<Usuario>) {
    const { data, error } = await supabase
      .from('Usuario')
      .insert([toDbRow(userData)])
      .select()
      .single();
    if (error) throw error;
    return data as Usuario;
  },

  async AtualizarUsuario(id: string, userData: Partial<Usuario>) {
    const { data, error } = await supabase
      .from('Usuario')
      .update({ ...toDbRow(userData), atualizado_em: new Date().toISOString() })
      .eq('id', id)
      .select()
      .single();
    if (error) throw error;
    return data as Usuario;
  },

  async DeletarUsuario(id: string) {
    const { error } = await supabase
      .from('Usuario')
      .delete()
      .eq('id', id);
    if (error) throw error;
    return true;
  },

  async PesquisaUsuarioPorEmail(email: string) {
    const { data, error } = await supabase
      .from('Usuario')
      .select('*')
      .eq('email', email)
      .maybeSingle();
    if (error) throw error;
    return data as Usuario | null;
  },
};

export default UsuarioDAO;
